import type { TransformedToken } from 'style-dictionary';

// exported variables from figma we do not want to export
const unusedRe = /ignore|color primitives|swatch/;

// tokens we are not ready for yet
const ignoreForNowRe = /typography|integer|font/;

export const filterUnused = (token: TransformedToken) => {
  return !unusedRe.test(token.name) && !ignoreForNowRe.test(token.name);
};
